import { Badge } from "@/components/ui/badge";
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@/components/ui/tabs";

import { apiClient, authService } from "@/App";
import { toast } from "sonner";

import {
  Users,
  UsersRound,
  CalendarCheck,
  ClipboardCheck,
  CheckCircle,
  XCircle,
  AlertTriangle,
  GraduationCap,
  Loader2,
} from "lucide-react";

const Dashboard = () => {
  const [stats, setStats] = useState(null);

  const [pending, setPending] = useState({
    pending_users: [],
    results: [],
    attendance: [],
    payments: [],
    announcements: [],
    inventory: [],
    totals: { all_pending_operations: 0 },
  });

  const [loading, setLoading] = useState(true);
  const [approvalLoading, setApprovalLoading] = useState(false);

  // =========================
  // USER + ROLE FIX
  // =========================
  const rawUser = authService.getUser() || {};

  const normalizeRole = (role) => {
    if (!role) return "";
    const r = role.toString().toLowerCase();

    if (r === "admin") return "school_admin";
    if (r === "schooladmin") return "school_admin";
    if (r === "superadmin") return "super_admin";

    return r;
  };

  const user = {
    ...rawUser,
    role: normalizeRole(rawUser.role),
  };

  const isAdmin =
    user.role === "school_admin" || user.role === "super_admin";

  // =========================
  // FETCH DASHBOARD DATA
  // =========================
  const fetchDashboardData = useCallback(async () => {
    try {
      setLoading(true);

      // STATS
      try {
        const statsRes = await apiClient.get("/dashboard/stats");
        setStats(statsRes?.data || {});
      } catch (err) {
        console.error(err);
        setStats({
          total_students: 0,
          total_staff: 0,
          present_today: 0,
          pending_approvals: 0,
        });
      }

      // ADMIN DATA
      if (isAdmin) {
        try {
          const res = await apiClient.get("/admin/pending");

          setPending({
            pending_users: res?.data?.pending_users || [],
            results: res?.data?.results || [],
            attendance: res?.data?.attendance || [],
            payments: res?.data?.payments || [],
            announcements: res?.data?.announcements || [],
            inventory: res?.data?.inventory || [],
            totals: res?.data?.totals || { all_pending_operations: 0 },
          });
        } catch (err) {
          console.error(err);

          setPending({
            pending_users: [],
            results: [],
            attendance: [],
            payments: [],
            announcements: [],
            inventory: [],
            totals: { all_pending_operations: 0 },
          });
        }
      }
    } catch (error) {
      console.error(error);
      toast.error("Failed to load dashboard");
    } finally {
      setLoading(false);
    }
  }, [isAdmin]);

  useEffect(() => {
    fetchDashboardData();
  }, [fetchDashboardData]);

  // =========================
  // APPROVAL HANDLER
  // =========================
  const handleApproval = async (itemType, itemId, action) => {
    try {
      setApprovalLoading(true);

      await apiClient.patch(
        `/admin/approve/${itemType}/${itemId}`,
        { action }
      );

      toast.success(`${itemType} ${action} successfully`);
      await fetchDashboardData();
    } catch (error) {
      toast.error(error?.response?.data?.detail || "Action failed");
    } finally {
      setApprovalLoading(false);
    }
  };

  // =========================
  // LOADING
  // =========================
  if (loading) {
    return (
      <div className="flex items-center justify-center h-[70vh]">
        <Loader2 className="w-5 h-5 animate-spin text-slate-400" />
      </div>
    );
  }

  // =========================
  // TABS (FIXED)
  // =========================
  const tabs = [
    {
      key: "pending_users",
      label: "Users",
      items: pending.pending_users,
      itemType: "user",
    },
    {
      key: "results",
      label: "Results",
      items: pending.results,
      itemType: "result",
    },
    {
      key: "attendance",
      label: "Attendance",
      items: pending.attendance,
      itemType: "attendance",
    },
    {
      key: "payments",
      label: "Payments",
      items: pending.payments,
      itemType: "payment",
    },
    {
      key: "announcements",
      label: "Announcements",
      items: pending.announcements,
      itemType: "announcement",
    },
    {
      key: "inventory",
      label: "Inventory",
      items: pending.inventory,
      itemType: "inventory",
    },
  ];

  const firstTab =
    tabs.find((t) => t.items?.length > 0)?.key || "pending_users";

  return (
    <div className="space-y-8">

      {/* HEADER */}
      <div>
        <h1 className="text-3xl font-bold text-white">
          Dashboard Overview
        </h1>

        <p className="text-slate-400 mt-1">
          Welcome back {user?.full_name || "User"}
        </p>
      </div>

      {/* ADMIN APPROVALS */}
      {isAdmin && (
        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardContent className="p-6">

            <div className="flex items-center gap-3 mb-6">
              <AlertTriangle className="w-5 h-5 text-amber-400" />
              <div>
                <h2 className="text-lg font-semibold text-white">
                  Pending Approvals
                </h2>
                <p className="text-sm text-slate-400">
                  {pending.totals.all_pending_operations} total items
                </p>
              </div>
            </div>

            {pending.totals.all_pending_operations === 0 ? (
              <div className="text-center py-10 text-emerald-400">
                No pending approvals
              </div>
            ) : (
              <Tabs defaultValue={firstTab}>
                <TabsList className="bg-[#0F172A] flex flex-wrap">

                  {tabs.map((tab) =>
                    tab.items?.length ? (
                      <TabsTrigger key={tab.key} value={tab.key}>
                        {tab.label} ({tab.items.length})
                      </TabsTrigger>
                    ) : null
                  )}

                </TabsList>

                {tabs.map((tab) =>
                  tab.items?.length ? (
                    <TabsContent key={tab.key} value={tab.key}>
                      <div className="space-y-3">

                        {tab.items.map((item) => (
                          <div
                            key={item.id}
                            className="p-4 bg-[#0F172A] rounded-xl flex justify-between"
                          >

                            <div>
                              <p className="text-white font-semibold">
                                {item.full_name ||
                                  item.title ||
                                  item.subject ||
                                  "Item"}
                              </p>

                              <p className="text-xs text-slate-400">
                                Submitted by{" "}
                                {item?.submitter?.full_name ||
                                  "Unknown"}
                              </p>
                            </div>

                            <div className="flex gap-2">

                              <Button
                                onClick={() =>
                                  handleApproval(
                                    tab.itemType,
                                    item.id,
                                    "approved"
                                  )
                                }
                              >
                                Approve
                              </Button>

                              <Button
                                variant="destructive"
                                onClick={() =>
                                  handleApproval(
                                    tab.itemType,
                                    item.id,
                                    "rejected"
                                  )
                                }
                              >
                                Reject
                              </Button>

                            </div>

                          </div>
                        ))}

                      </div>
                    </TabsContent>
                  ) : null
                )}

              </Tabs>
            )}

          </CardContent>
        </Card>
      )}

    </div>
  );
};

export default Dashboard;
